arguments.file_text:
namespace sv_f374bd099b254d139d5d332cda0a1705.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_f374bd099b254d139d5d332cda0a1705.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h5>Channels</h5>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name-row">
                            <span class="channel-name"># @channel.Name</span>
                            @if (channel.UnreadCount > 0)
                            {
                                <span class="badge bg-danger unread-badge">@channel.UnreadCount</span>
                            }
                        </div>
                        <span class="channel-desc">@Truncate(channel.Description, 40)</span>
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <main class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h5># @_activeChannel.Name</h5>
                <span class="text-muted">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="OnMainScroll" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="text-center p-2"><span class="spinner-border spinner-border-sm"></span> Loading…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="msg-header-row">
                                <strong class="msg-author">@msg.Author</strong>
                                <span class="msg-time">@RelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="btn btn-sm reaction-chip"
                                                title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter indicator *@
                            @if (_threadSummaries.TryGetValue(msg.Id, out var ts))
                            {
                                <button class="btn btn-link btn-sm thread-link p-0"
                                        @onclick="() => OpenThreadAsync(msg)">
                                    💬 @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                    — last @RelativeTime(ts.LastReplyAt)
                                </button>
                            }

                            @* Hover action buttons *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="msg-actions">
                                    <button class="btn btn-outline-secondary btn-sm" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="btn btn-outline-secondary btn-sm"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀+
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker-popup">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="btn btn-sm emoji-btn"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            @* Message input *@
            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Type a message…"
                          @bind="_newMessage" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown"></textarea>
                <button class="btn btn-primary send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessage)"
                        @onclick="SendMainMessageAsync">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <span>Select a channel to start chatting</span>
            </div>
        }
    </main>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h6>Thread</h6>
                <button class="btn btn-sm btn-outline-secondary" @onclick="CloseThread">✕</button>
            </div>

            <div class="thread-root-quote">
                <strong>@_threadRootMessage.Author</strong>
                <span class="msg-time">@RelativeTime(_threadRootMessage.SentAt)</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-bubble">
                            <div class="msg-header-row">
                                <strong class="msg-author">@reply.Author</strong>
                                <span class="msg-time">@RelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="btn btn-sm reaction-chip"
                                                title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Reply in thread…"
                          @bind="_threadReply" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"></textarea>
                <button class="btn btn-primary send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReply)"
                        @onclick="SendThreadReplyAsync">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Data ──
    private List<Channel>? _channels;
    private List<Message>? _messages;
    private List<Message>? _threadMessages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // ── UI state ──
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private string _newMessage = string.Empty;
    private string _threadReply = string.Empty;
    private bool _loadingOlder;
    private bool _allOlderLoaded;
    private ElementReference _messageListRef;

    private const int PageSize = 30;
    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _allOlderLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);
        await BuildThreadSummariesAsync();
        CloseThread();
        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Messaging ──

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _newMessage = string.Empty;
        _messages ??= new();
        _messages.Add(sent);
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Scroll-to-top pagination ──

    private async Task OnMainScroll()
    {
        // The actual scroll position check requires JS interop; this handler fires on
        // any scroll. A JS helper would call back when scrollTop ≈ 0. For robustness
        // we provide a simplified approach that the host can enhance with JS interop.
        // Here we expose the method for potential JS invocation.
    }

    /// <summary>Called from JS interop when the user scrolls to the top of the message list.</summary>
    [JSInvokable]
    public async Task LoadOlderMessagesAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannelId is null || _messages is null) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count < PageSize) _allOlderLoaded = true;
        _messages.InsertRange(0, older);
        await BuildThreadSummariesAsync();

        _loadingOlder = false;
        StateHasChanged();
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;
        await RefreshCurrentChannel();
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        await RefreshCurrentChannel();
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReply = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
        _threadReply = string.Empty;
        _threadMessages ??= new();
        _threadMessages.Add(reply);
        await BuildThreadSummariesAsync();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──

    private async Task RefreshCurrentChannel()
    {
        if (_activeChannelId is null) return;
        _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages?.Count ?? PageSize);
        await BuildThreadSummariesAsync();

        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private async Task BuildThreadSummariesAsync()
    {
        if (_messages is null) return;

        _threadSummaries.Clear();

        // Identify root messages (those that have replies among loaded messages)
        var replyGroups = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.ToList();
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                replies.Count,
                replies.Max(r => r.SentAt)
            );
        }
    }

    private static string RelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 5 => "just now",
            < 60 => $"{(int)diff.TotalSeconds}s ago",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
