toolArgs.file_text:
/* ── Container ── */
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: inherit;
}

/* ── Left Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #1a1b2e;
}

.sidebar-header {
    padding: 1rem;
    border-bottom: 1px solid rgba(255,255,255,.1);
}

.sidebar-header h5 {
    margin: 0;
    font-weight: 700;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: .05em;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: .6rem 1rem;
    cursor: pointer;
    transition: background .15s;
}

.channel-item:hover {
    background: rgba(255,255,255,.08);
}

.channel-item.active {
    background: rgba(255,255,255,.15);
    border-left: 3px solid #8d99ae;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: .9rem;
}

.unread-badge {
    font-size: .7rem;
    min-width: 20px;
    border-radius: 10px;
}

.channel-desc {
    font-size: .75rem;
    color: #8d99ae;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ── Main Message Area ── */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width .2s ease;
}

.message-area.expanded {
    width: 80%;
}

.message-header {
    padding: .75rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
}

.message-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: .75rem 1.25rem;
}

.message-bubble {
    position: relative;
    padding: .5rem .75rem;
    margin-bottom: .25rem;
    border-radius: 6px;
    transition: background .1s;
}

.message-bubble:hover {
    background: #f0f2f5;
}

.msg-header-row {
    display: flex;
    align-items: baseline;
    gap: .5rem;
}

.msg-author {
    font-size: .875rem;
}

.msg-time {
    font-size: .75rem;
    color: #6c757d;
}

.msg-content {
    font-size: .9rem;
    line-height: 1.45;
    margin-top: 2px;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-chip {
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 12px;
    font-size: .8rem;
    padding: 1px 8px;
    cursor: pointer;
    line-height: 1.5;
}

.reaction-chip:hover {
    background: #d4d8dd;
}

/* ── Thread link ── */
.thread-link {
    font-size: .8rem;
    text-decoration: none;
}

/* ── Hover action buttons ── */
.msg-actions {
    position: absolute;
    top: .25rem;
    right: .5rem;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 6px rgba(0,0,0,.1);
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker-popup {
    position: absolute;
    right: 0;
    top: 100%;
    margin-top: 4px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 4px 12px rgba(0,0,0,.15);
    z-index: 10;
    white-space: nowrap;
}

.emoji-btn {
    font-size: 1.15rem;
    padding: 2px 4px;
    border: none;
    background: transparent;
    cursor: pointer;
    border-radius: 4px;
}

.emoji-btn:hover {
    background: #e9ecef;
}

/* ── Message input area ── */
.message-input-area {
    display: flex;
    gap: .5rem;
    padding: .75rem 1.25rem;
    border-top: 1px solid #dee2e6;
    background: #f8f9fa;
    align-items: flex-end;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    font-size: .9rem;
}

.send-btn {
    align-self: flex-end;
    white-space: nowrap;
}

/* ── Right Panel: Thread ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #dee2e6;
    background: #fdfdfe;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: .75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
}

.thread-header h6 {
    margin: 0;
    font-weight: 700;
}

.thread-root-quote {
    padding: .75rem 1rem;
    background: #eef1f5;
    border-bottom: 1px solid #dee2e6;
    font-size: .85rem;
}

.thread-root-quote p {
    margin: .25rem 0 0;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: .5rem 1rem;
}

